{
  "grammar": [
    {
      "pattern": "先 + action1 + 然後 + action2 + 再 + action3 + 最後 + action4",
      "structure": ["先", "action1", "然後", "action2", "再", "action3", "最後", "action4"],
      "explanation_en": "Use this structure to describe a sequence of actions in order. '先' means 'first', '然後' means 'then', '再' means 'next', and '最後' means 'finally'. This is common in daily planning and instructions.",
      "title": "Sequencing Actions with 先…然後…再…最後",
      "meaning": "First do A, then B, next C, finally D",
      "when_to_use": ["When giving step-by-step instructions", "When describing your daily routine", "When planning an itinerary"],
      "when_not_to_use": ["When actions happen simultaneously", "When the order is not important"],
      "pragmatic_notes": "In Taiwan, this structure is very common in both formal and informal contexts. You can omit some steps if the sequence is shorter, e.g., 先吃早餐然後去上班.",
      "word_order_notes": "The order of actions must follow the actual chronological sequence. Each action is a verb phrase.",
      "english_contrast": "English uses 'first...then...next...finally' similarly, but Chinese requires 先 before the first action, not at the end.",
      "korean_contrast": "Korean uses '먼저...그리고...다음에...마지막으로' but the word order is more flexible. Chinese strictly follows the sequence.",
      "negative_examples": [
        {
          "text": "先然後吃早餐去上班",
          "error": "Missing action after 先 and before 然後"
        }
      ],
      "incorrect_examples": [
        {
          "text": "先吃早餐然後去上班再",
          "error": "再 should be followed by an action, not placed at the end"
        }
      ],
      "transformation_drills": ["Change '先起床然後刷牙' to include 再吃早餐 and 最後去上班"],
      "production_drills": ["Describe your morning routine using 先…然後…再…最後"],
      "common_error_patterns": ["Omitting the action after 先", "Placing 再 at the end without an action"],
      "repair_feedback": {
        "word_order": "Make sure each step has a verb after 先, 然後, 再, 最後",
        "politeness": "This structure is neutral; add 請 for polite instructions",
        "vocabulary": "Use appropriate daily verbs like 起床, 吃, 去, 喝"
      }
    },
    {
      "pattern": "Subject + 比 + object + adjective",
      "structure": ["subject", "比", "object", "adjective"],
      "explanation_en": "Use this structure to compare two things. The adjective comes after the object, not before. This is the basic comparative form in Chinese.",
      "title": "Comparisons with 比",
      "meaning": "A is more adjective than B",
      "when_to_use": ["When comparing two items", "When stating which is better/cheaper/faster", "In shopping or choosing between options"],
      "when_not_to_use": ["When comparing three or more items (use 最 instead)", "When the comparison is equal (use 一樣)"],
      "pragmatic_notes": "In Taiwan, 比 is used in both casual and formal speech. For politeness, avoid comparing people directly unless close friends.",
      "word_order_notes": "The adjective must come after the object, not before. Do not use 很 before the adjective in a 比 sentence.",
      "english_contrast": "English says 'A is bigger than B', but Chinese says 'A 比 B big'. No 'than' equivalent needed.",
      "korean_contrast": "Korean uses 'A가 B보다 adjective' (e.g., A가 B보다 커요). Chinese order is similar: subject 比 object adjective.",
      "negative_examples": [
        {
          "text": "這個書比那個很貴",
          "error": "Do not use 很 before the adjective in a 比 sentence"
        }
      ],
      "incorrect_examples": [
        {
          "text": "這個比那個書貴",
          "error": "The object should be '那個書', not split"
        }
      ],
      "transformation_drills": ["Change '這個書很貴' to a comparison with 那個書"],
      "production_drills": ["Compare two drinks using 比, e.g., 紅茶比綠茶便宜"],
      "common_error_patterns": ["Adding 很 before the adjective", "Wrong word order (adjective before object)"],
      "repair_feedback": {
        "word_order": "Remember: subject 比 object adjective, no 很",
        "politeness": "Use 比較 for softer comparisons in polite contexts",
        "vocabulary": "Use adjectives like 貴, 便宜, 大, 小, 快, 慢"
      }
    },
    {
      "pattern": "Subject + 在 + location + action",
      "structure": ["subject", "在", "location", "action"],
      "explanation_en": "Use this structure to indicate where an action takes place. 在 is a preposition meaning 'at/in/on'. The location comes before the action.",
      "title": "Location of Actions with 在",
      "meaning": "Subject does action at location",
      "when_to_use": ["When saying where you do something", "When giving directions", "When describing daily activities"],
      "when_not_to_use": ["When the location is the destination (use 去 instead)", "When the location is the source (use 從 instead)"],
      "pragmatic_notes": "In Taiwan, 在 is used for both static locations (e.g., 在學校) and actions happening there. For movement, use 去 or 來.",
      "word_order_notes": "The location phrase must come before the action, not after. This is different from English where location often comes after the verb.",
      "english_contrast": "English says 'I eat at the restaurant', but Chinese says 'I at the restaurant eat'. Location before verb.",
      "korean_contrast": "Korean uses '에서' after the location (e.g., 식당에서 먹어요). Chinese uses 在 before the location.",
      "negative_examples": [
        {
          "text": "我吃在餐廳",
          "error": "Location should come before the action, not after"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我在餐廳吃早餐在早上",
          "error": "Time phrase should come before or after the location, not split the location and action"
        }
      ],
      "transformation_drills": ["Change '我吃早餐' to include 在餐廳"],
      "production_drills": ["Say where you do three daily activities using 在"],
      "common_error_patterns": ["Placing location after the verb", "Confusing 在 with 去"],
      "repair_feedback": {
        "word_order": "Location must come before the action verb",
        "politeness": "Neutral; add 請 for polite requests about location",
        "vocabulary": "Use location words like 學校, 公司, 家, 餐廳, 公園"
      }
    }
  ]
}
